sql:
SELECT name, uniprotkb_ac
FROM enzymes
ORDER BY name ASC;

SELECT TRUNC(temperature) AS truncated_temperature, pH
FROM reaction_conditions
WHERE reaction_id = 1 AND created_date = '2023-05-01 12:00:00';

SELECT COUNT(*) AS dataset_count
FROM reaction_datasets
WHERE description LIKE '%glucose metabolism-related reactions%';

external_knowledge:
- In biochemistry, 'kcat' represents the turnover number of an enzyme-catalyzed reaction, which is a measure of how many substrate molecules the enzyme can convert to product per unit time; 
- 'Km' (Michaelis constant) is a measure of the binding affinity of the enzyme for its substrate, with lower Km values indicating higher affinity; 
- Enzyme variants refer to different forms of an enzyme that may have different properties or activities; 
- Reaction conditions such as temperature, pH, buffer, ionic strength, and pressure are crucial in determining the rate and efficiency of enzyme-catalyzed reactions.

sql:
SELECT name
FROM reactions
ORDER BY name ASC;

SELECT reaction_id, MAX(value) AS max_value
FROM kinetic_parameters
GROUP BY reaction_id;

SELECT name, created_date
FROM reactions
ORDER BY created_date DESC;

SELECT COUNT(reaction_id) AS glucose_metabolism_reactions
FROM reaction_tags
WHERE tag = 'glucose metabolism';
